module adder_pipe_64bit(
    input clk, input rst_n, input i_en, input [63:0] adda, input [63:0] addb,
    output reg [64:0] result, output reg o_en
);

    reg [63:0] adda_reg, addb_reg;
    reg i_en_reg;

    reg [63:0] carry_reg1, carry_reg2, carry_reg3, carry_reg4, carry_reg5, carry_reg6;

    reg [64:0] result_reg1, result_reg2, result_reg3, result_reg4, result_reg5, result_reg6;

    reg o_en_reg1, o_en_reg2, o_en_reg3, o_en_reg4, o_en_reg5, o_en_reg6;

    wire [64:0] sum = adda_reg + addb_reg + carry_reg6;
    wire [63:0] carry = {sum[64], sum[63:1]};

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            adda_reg <= 0;
            addb_reg <= 0;
            i_en_reg <= 0;
            carry_reg1 <= 0;
            carry_reg2 <= 0;
            carry_reg3 <= 0;
            carry_reg4 <= 0;
            carry_reg5 <= 0;
            carry_reg6 <= 0;
            result_reg1 <= 0;
            result_reg2 <= 0;
            result_reg3 <= 0;
            result_reg4 <= 0;
            result_reg5 <= 0;
            result_reg6 <= 0;
            o_en_reg1 <= 0;
            o_en_reg2 <= 0;
            o_en_reg3 <= 0;
            o_en_reg4 <= 0;
            o_en_reg5 <= 0;
            o_en_reg6 <= 0;
        end else begin
            adda_reg <= adda;
            addb_reg <= addb;
            i_en_reg <= i_en;
            carry_reg1 <= carry;
            carry_reg2 <= carry_reg1;
            carry_reg3 <= carry_reg2;
            carry_reg4 <= carry_reg3;
            carry_reg5 <= carry_reg4;
            carry_reg6 <= carry_reg5;
            result_reg1 <= sum;
            result_reg2 <= result_reg1;
            result_reg3 <= result_reg2;
            result_reg4 <= result_reg3;
            result_reg5 <= result_reg4;
            result_reg6 <= result_reg5;
            o_en_reg1 <= i_en_reg;
            o_en_reg2 <= o_en_reg1;
            o_en_reg3 <= o_en_reg2;
            o_en_reg4 <= o_en_reg3;
            o_en_reg5 <= o_en_reg4;
            o_en_reg6 <= o_en_reg5;
        end
    end

    always @(*) begin
        result = result_reg6;
        o_en = o_en_reg6;
    end
endmodule

